import React from 'react';

const skillsData = [
  { name: 'HTML & CSS', level: 85, sym: '✕', color: '#7fc5e8' },
  { name: 'JavaScript', level: 70, sym: '○', color: '#e87b7b' },
  { name: 'React', level: 60, sym: '□', color: '#e87bce' },
  { name: 'Bootstrap', level: 75, sym: '△', color: '#7be8b4' },
  { name: 'Tailwind CSS', level: 60, sym: '✕', color: '#7fc5e8' },
  { name: 'Git & GitHub', level: 65, sym: '○', color: '#e87b7b' },
];

const Skills = () => (
  <section
    id="Skills"
    className="min-h-screen flex flex-col justify-center items-center px-5 py-24"
    style={{ background: 'var(--ps-dark, #00052b)' }}
  >
    <h1 className="ps-title font-bold text-4xl text-white text-center mb-12">
      Skills
    </h1>

    <div className="w-full max-w-2xl flex flex-col gap-5">
      {skillsData.map((skill, i) => (
        <div
          key={i}
          className="rounded-xl p-6 transition-transform duration-300 hover:-translate-y-1"
          style={{
            background: 'rgba(0,55,145,0.15)',
            border: `1px solid ${skill.color}44`,
            borderLeft: `3px solid ${skill.color}`,
          }}
        >
          {/* Header */}
          <div className="flex items-center gap-3 mb-2">
            <span
              style={{
                display: 'inline-flex',
                alignItems: 'center',
                justifyContent: 'center',
                width: '28px',
                height: '28px',
                borderRadius: '50%',
                border: `1.5px solid ${skill.color}`,
                color: skill.color,
                fontSize: '13px',
                flexShrink: 0,
              }}
            >
              {skill.sym}
            </span>

            <h3 className="font-bold text-base" style={{ color: skill.color }}>
              {skill.name}
            </h3>
          </div>

          {/* TEXT ONLY (no bars, no extras) */}
          <p className="text-sm mt-2" style={{ color: 'rgba(255,255,255,0.6)' }}>
            Proficiency Level: {skill.level}%
          </p>
        </div>
      ))}
    </div>
  </section>
);

export default Skills;
